const sd = $getWorkflowStaticData('global');
const meta = $('URL Validator').first().json;
const now = Date.now();
const ttlMs = 2 * 60 * 60 * 1000;
const frontendData = $json.frontendData || {};

let existing = {};
try {
  existing = JSON.parse(sd[meta.jobId] || '{}');
} catch (e) {}

sd[meta.jobId] = JSON.stringify({
  status: 'done',
  data: frontendData,
  request: {
    url: meta.url,
    domain: meta.domain || frontendData?.meta?.domain || null,
    ip: meta.ip || '',
    ua: meta.ua || '',
  },
  storedAt: existing.storedAt || now,
  updatedAt: now,
  finishedAt: now,
  expiresAt: now + ttlMs,
});

const hour = Math.floor(now / (60 * 60 * 1000));
for (const key of Object.keys(sd)) {
  if (key.startsWith('job_')) {
    try {
      const entry = JSON.parse(sd[key]);
      if (entry.expiresAt && entry.expiresAt < now) delete sd[key];
    } catch (e) {
      delete sd[key];
    }
    continue;
  }

  if (key.startsWith('rl:')) {
    const keyHour = parseInt(key.split(':')[2] || '0', 10);
    if (Number.isFinite(keyHour) && keyHour < hour - 1) delete sd[key];
  }
}

return [{
  json: {
    stored: true,
    jobId: meta.jobId,
    domain: frontendData?.meta?.domain || meta.domain || null,
    frontendData,
  },
}];

const sd = $getWorkflowStaticData('global');
const req = $('Webhook Status').first().json || {};
const jobId = req.query?.jobId || req.params?.jobId || '';

if (!jobId || !jobId.startsWith('job_')) {
  return [{ json: { ok: false, status: 'error', error: 'Ungültige Job-ID.' } }];
}

const raw = sd[jobId];
if (!raw) {
  return [{ json: { ok: true, status: 'processing', jobId, message: 'Audit läuft noch...' } }];
}

let entry;
try {
  entry = JSON.parse(raw);
} catch (e) {
  return [{ json: { ok: false, status: 'error', jobId, error: 'Fehler beim Laden.' } }];
}

if (entry.expiresAt && entry.expiresAt < Date.now()) {
  delete sd[jobId];
  return [{ json: { ok: false, status: 'expired', jobId, error: 'Ergebnis abgelaufen.' } }];
}

if (entry.status === 'done') {
  return [{ json: { ok: true, status: 'done', jobId, data: entry.data } }];
}

if (entry.status === 'error') {
  return [{ json: { ok: false, status: 'error', jobId, error: entry.error || 'Audit fehlgeschlagen.' } }];
}

return [{ json: { ok: true, status: entry.status || 'processing', jobId, message: entry.message || 'Audit läuft noch...' } }];

const req = $input.first().json || {};
const body = req.body || {};
const ui = body.__submission?.user_inputs || body;
const errors = [];

const name = (ui.name || body.name || '').toString().trim();
const email = (ui.email || body.email || '').toString().trim();
const company = (ui.company || body.company || '').toString().trim();
const message = (ui.message || body.message || '').toString().trim();
const jobId = (ui.jobId || body.jobId || '').toString().trim();
const url = (ui.url || body.url || '').toString().trim();
const domain = (ui.domain || body.domain || '').toString().trim();
const primaryFinding = (ui.primaryFinding || body.primaryFinding || '').toString().trim();
const ip = (body.__submission?.ip || req.ip || req.headers?.['x-forwarded-for'] || '').toString();
const ua = (body.__submission?.browser || req.headers?.['user-agent'] || '').toString();

if (!name) errors.push('Bitte Ihren Namen angeben.');
if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errors.push('Bitte eine gueltige E-Mail-Adresse angeben.');

const subject = '[Audit] Beratung angefragt - ' + (company || domain || name);
const lines = [
  'Neue Beratungsanfrage aus dem Audit.',
  '',
  'Name: ' + name,
  'E-Mail: ' + email,
  company ? 'Unternehmen: ' + company : null,
  domain ? 'Domain: ' + domain : null,
  url ? 'URL: ' + url : null,
  jobId ? 'Job ID: ' + jobId : null,
  primaryFinding ? 'Primaerer Befund: ' + primaryFinding : null,
  '',
  'Nachricht:',
  message || '(keine Zusatznachricht)'
].filter(Boolean);

const text = lines.join('\n');
const html = [
  '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;line-height:1.6;color:#0f172a;">',
  '<h2 style="margin:0 0 16px;">Neue Beratungsanfrage aus dem Audit</h2>',
  '<p><strong>Name:</strong> ' + name + '</p>',
  '<p><strong>E-Mail:</strong> ' + email + '</p>',
  company ? '<p><strong>Unternehmen:</strong> ' + company + '</p>' : '',
  domain ? '<p><strong>Domain:</strong> ' + domain + '</p>' : '',
  url ? '<p><strong>URL:</strong> ' + url + '</p>' : '',
  jobId ? '<p><strong>Job ID:</strong> ' + jobId + '</p>' : '',
  primaryFinding ? '<p><strong>Primaerer Befund:</strong> ' + primaryFinding + '</p>' : '',
  '<hr style="border:none;border-top:1px solid #e2e8f0;margin:20px 0;">',
  '<p><strong>Nachricht:</strong></p>',
  '<p>' + (message || '(keine Zusatznachricht)').replace(/\n/g, '<br>') + '</p>',
  '</div>'
].join('');

return [{ json: {
  ok: errors.length === 0,
  error: errors.length ? errors.join(' ') : null,
  name,
  email,
  company,
  message,
  jobId,
  url,
  domain,
  primaryFinding,
  ip,
  ua,
  subject,
  text,
  html,
  submittedAt: new Date().toISOString(),
} }];
